-- ----------------------------------------------------------------------------
-- Drop pass: every rulebook-owned view, reverse iteration order, CASCADE.
-- The rulebook is HEAD — the surviving view set must mirror it exactly.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_treatment_rankings CASCADE;
DROP VIEW IF EXISTS vw_stratum_variables CASCADE;
DROP VIEW IF EXISTS vw_model_summary CASCADE;
DROP VIEW IF EXISTS vw_stratum_summaries CASCADE;
DROP VIEW IF EXISTS vw_case_cells CASCADE;
DROP VIEW IF EXISTS vw_strata CASCADE;
DROP VIEW IF EXISTS vw_treatments CASCADE;
DROP VIEW IF EXISTS vw_studies CASCADE;
DROP VIEW IF EXISTS vw_loops CASCADE;

-- ----------------------------------------------------------------------------
-- vw_loops: Table: Loops — the 10-loop build plan, carried as a first-class entity inside the model. Each row documents what new concept is introduced and why.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_loops CASCADE;
CREATE VIEW vw_loops WITH (security_invoker = ON) AS
SELECT
  t.loop_id,                                                                    -- Unique identifier: loop-01 through loop-10.
  calc_loops_name(t.loop_id) AS name,                                           -- Display label.
  t.title,                                                                      -- Short title for what this loop adds to the domain model.
  t.status,                                                                     -- planned | in-progress | complete
  t.new_concept,                                                                -- The new first-class domain concept introduced this loop.
  t.domain_question,                                                            -- The natural-language question this loop's concept answers FROM the domain data.
  t.mock_data_note,                                                             -- What the seed data is designed to show.
  t.next_suggestion                                                             -- Suggestion for the next loop, written after witnessing the DAG at this loop's end.
FROM loops t;

-- ----------------------------------------------------------------------------
-- vw_studies: Table: Studies — a clinical or empirical study comparing two or more treatments for a condition, with patient cases stratified by a confounding variable. The top-level entity in the domain.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_studies CASCADE;
CREATE VIEW vw_studies WITH (security_invoker = ON) AS
SELECT
  t.study_id,                                                                   -- Unique slug for this study (e.g. kidney-1986, berkeley-1973).
  calc_studies_name(t.study_id) AS name,                                        -- Display label, mirrors StudyId.
  t.title,                                                                      -- Human-readable title of the study.
  t.source,                                                                     -- Citation or description of the original data source.
  t.source_url,                                                                 -- URL to the original source.
  calc_studies_total_cases(t.study_id) AS total_cases,                          -- Total number of cases (trials) across all CaseCells in this study.
  calc_studies_cell_count(t.study_id) AS cell_count                             -- Number of CaseCell rows for this study.
FROM studies t;

-- ----------------------------------------------------------------------------
-- vw_treatments: Table: Treatments — the interventions being compared within a study. Each treatment belongs to one study.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_treatments CASCADE;
CREATE VIEW vw_treatments WITH (security_invoker = ON) AS
SELECT
  t.treatment_id,                                                               -- Unique slug (e.g. kidney-1986-A, kidney-1986-B).
  calc_treatments_name(t.treatment_id) AS name,                                 -- Display label.
  t.study,                                                                      -- FK to the parent Study.
  t.treatment_label,                                                            -- Short label used in CaseCells and comparisons (e.g. A, B).
  t.description,                                                                -- Plain-language description of what this treatment is.
  calc_treatments_total_cases(t.treatment_id) AS total_cases,                   -- Total cases for this treatment across all strata.
  calc_treatments_total_successes(t.treatment_id) AS total_successes,           -- Total successes for this treatment across all strata.
  calc_treatments_pooled_success_rate(t.treatment_id) AS pooled_success_rate    -- Pooled (across all strata) success rate for this treatment: TotalSuccesses / TotalCases.
FROM treatments t;

-- ----------------------------------------------------------------------------
-- vw_strata: Table: Strata — the subdivisions of patients within a study by the value of the confounding variable (e.g. stone size). Each stratum belongs to one study.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_strata CASCADE;
CREATE VIEW vw_strata WITH (security_invoker = ON) AS
SELECT
  t.stratum_id,                                                                 -- Unique slug (e.g. kidney-1986-small, kidney-1986-large).
  calc_strata_name(t.stratum_id) AS name,                                       -- Display label.
  t.study,                                                                      -- FK to the parent Study.
  t.stratum_label,                                                              -- Short label used in CaseCells (e.g. small, large, dept-A).
  t.description,                                                                -- Plain-language description of what defines this stratum.
  calc_strata_total_cases(t.stratum_id) AS total_cases                          -- Total cases in this stratum across all treatments.
FROM strata t;

-- ----------------------------------------------------------------------------
-- vw_case_cells: Table: CaseCells — the raw leaves of the DAG. One row per (study, stratum, treatment) combination recording the aggregate count of successes and total cases. Every derived fact in the model traces back to these numbers. Nothing above this row is a raw input.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_case_cells CASCADE;
CREATE VIEW vw_case_cells WITH (security_invoker = ON) AS
SELECT
  t.case_cell_id,                                                               -- Unique slug (e.g. kidney-1986-small-A).
  calc_case_cells_name(t.case_cell_id) AS name,                                 -- Display label.
  t.study,                                                                      -- FK to the parent Study.
  t.stratum_label,                                                              -- The stratum this cell belongs to (matches Strata.StratumLabel).
  t.treatment_label,                                                            -- The treatment applied in this cell (matches Treatments.TreatmentLabel).
  t.successes,                                                                  -- Number of patients in this cell who had a successful outcome. RAW INPUT — never derived.
  t.cases,                                                                      -- Total number of patients in this cell. RAW INPUT — never derived.
  calc_case_cells_cell_success_rate(t.case_cell_id) AS cell_success_rate,       -- Success rate within this cell: Successes / Cases. The first derived fact in the DAG.
  calc_case_cells_total_cases_for_treatment(t.case_cell_id) AS total_cases_for_treatment,-- Total cases across ALL strata for this treatment in this study — the denominator for TreatmentExposureFraction.
  calc_case_cells_treatment_exposure_fraction(t.case_cell_id) AS treatment_exposure_fraction-- Fraction of this treatment's total cases that fall in this stratum: Cases / TotalCasesForTreatment. High imbalance across strata is the mechanism of confounding — when treatments are allocated very differently across strata, the pooled rate conflates treatment effect with stratum difficulty.
FROM case_cells t;

-- ----------------------------------------------------------------------------
-- vw_stratum_summaries: Table: StratumSummaries — one row per (study, stratum, treatment). Computes the success rate WITHIN each stratum for each treatment. This is the stratified view that contradicts the pooled conclusion when a Simpson's Paradox reversal is present. Each row belongs to both a Stratum and a Treatment in the same Study.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_stratum_summaries CASCADE;
CREATE VIEW vw_stratum_summaries WITH (security_invoker = ON) AS
SELECT
  t.stratum_summary_id,                                                         -- Unique slug (e.g. kidney-1986-small-A).
  calc_stratum_summaries_name(t.stratum_summary_id) AS name,                    -- Display label.
  t.study,                                                                      -- FK to the parent Study.
  t.stratum_label,                                                              -- Which stratum (matches Strata.StratumLabel).
  t.treatment_label,                                                            -- Which treatment (matches Treatments.TreatmentLabel).
  calc_stratum_summaries_stratum_successes(t.stratum_summary_id) AS stratum_successes,-- Total successes in this (stratum, treatment) cell for this study.
  calc_stratum_summaries_stratum_cases(t.stratum_summary_id) AS stratum_cases,  -- Total cases in this (stratum, treatment) cell for this study.
  calc_stratum_summaries_stratum_success_rate(t.stratum_summary_id) AS stratum_success_rate,-- Success rate within this stratum for this treatment: StratumSuccesses / StratumCases. The true per-stratum picture.
  calc_stratum_summaries_stratum_successes_a(t.stratum_summary_id) AS stratum_successes_a,-- Successes for treatment A in this (study, stratum) — used to determine the per-stratum winner.
  calc_stratum_summaries_stratum_cases_a(t.stratum_summary_id) AS stratum_cases_a,-- Cases for treatment A in this (study, stratum).
  calc_stratum_summaries_stratum_rate_a(t.stratum_summary_id) AS stratum_rate_a,-- Success rate for treatment A in this stratum.
  calc_stratum_summaries_stratum_successes_b(t.stratum_summary_id) AS stratum_successes_b,-- Successes for treatment B in this (study, stratum).
  calc_stratum_summaries_stratum_cases_b(t.stratum_summary_id) AS stratum_cases_b,-- Cases for treatment B in this (study, stratum).
  calc_stratum_summaries_stratum_rate_b(t.stratum_summary_id) AS stratum_rate_b,-- Success rate for treatment B in this stratum.
  calc_stratum_summaries_stratum_winner(t.stratum_summary_id) AS stratum_winner,-- Which treatment wins in this stratum: 'A' if StratumRateA > StratumRateB, else 'B'. Used by TreatmentRankings to detect paradox.
  calc_stratum_summaries_study_total_cases(t.stratum_summary_id) AS study_total_cases,-- Total cases across ALL strata and ALL treatments in this study. The denominator for StratumFraction.
  calc_stratum_summaries_stratum_total_cases(t.stratum_summary_id) AS stratum_total_cases,-- Total cases in this stratum across both treatments (A + B combined). Numerator for StratumFraction.
  calc_stratum_summaries_stratum_fraction(t.stratum_summary_id) AS stratum_fraction,-- Fraction of the study's total cases that fall in this stratum: StratumTotalCases / StudyTotalCases. The weight the confounder assigns to each stratum. A large StratumFraction on a low-success stratum pulls the pooled rate down; when that stratum is also over-allocated to one treatment, it creates the reversal.
  calc_stratum_summaries_weighted_stratum_rate(t.stratum_summary_id) AS weighted_stratum_rate,-- StratumFraction × StratumSuccessRate. The contribution of this (stratum, treatment) row to the study-level pooled rate. Summing WeightedStratumRate across all strata for a given treatment reconstructs that treatment's pooled rate from stratum weights — witnessing the mechanism equation.
  calc_stratum_summaries_treatment_a_cases_here(t.stratum_summary_id) AS treatment_a_cases_here,-- Cases for treatment A in this stratum — used to compute TreatmentA's allocation fraction in this stratum.
  calc_stratum_summaries_treatment_b_cases_here(t.stratum_summary_id) AS treatment_b_cases_here,-- Cases for treatment B in this stratum — used to compute TreatmentB's allocation fraction in this stratum.
  calc_stratum_summaries_treatment_a_total_cases(t.stratum_summary_id) AS treatment_a_total_cases,-- Total cases for treatment A across all strata in this study — denominator for AllocationFractionA.
  calc_stratum_summaries_treatment_b_total_cases(t.stratum_summary_id) AS treatment_b_total_cases,-- Total cases for treatment B across all strata in this study — denominator for AllocationFractionB.
  calc_stratum_summaries_allocation_fraction_a(t.stratum_summary_id) AS allocation_fraction_a,-- Fraction of treatment A's total cases that land in this stratum: TreatmentACasesHere / TreatmentATotalCases. Equivalent to TreatmentExposureFraction for A.
  calc_stratum_summaries_allocation_fraction_b(t.stratum_summary_id) AS allocation_fraction_b,-- Fraction of treatment B's total cases that land in this stratum: TreatmentBCasesHere / TreatmentBTotalCases.
  calc_stratum_summaries_allocation_bias(t.stratum_summary_id) AS allocation_bias-- AllocationFractionA minus AllocationFractionB: how much more of treatment A (relative to B) is concentrated in this stratum. Positive = A is over-allocated here; negative = B is over-allocated here. When AllocationBias is large and negative in a low-success stratum, treatment A is under-represented in the hard cases — making A look worse in the pooled view than it is in any stratum. This is the confounder's fingerprint as a signed number.
FROM stratum_summaries t;

-- ----------------------------------------------------------------------------
-- vw_model_summary: Table: ModelSummary — one row describing the epistemic coverage of this entire model instance. Aggregates across all TreatmentRankings to witness how many studies were examined, how many showed a full reversal, how many were explained, and the average paradox strength. The model holds a mirror to itself.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_model_summary CASCADE;
CREATE VIEW vw_model_summary WITH (security_invoker = ON) AS
SELECT
  t.model_summary_id,                                                           -- Unique identifier for this model instance.
  calc_model_summary_name(t.model_summary_id) AS name,                          -- Display label.
  calc_model_summary_reversal_count(t.model_summary_id) AS reversal_count,      -- Number of studies with IsReversal=TRUE (strict full reversal).
  calc_model_summary_non_reversal_count(t.model_summary_id) AS non_reversal_count,-- Number of studies with IsReversal=FALSE.
  calc_model_summary_study_count(t.model_summary_id) AS study_count,            -- Total number of TreatmentRankings in this model: ReversalCount + NonReversalCount.
  calc_model_summary_explained_count(t.model_summary_id) AS explained_count,    -- Number of studies with IsParadoxExplained=TRUE (reversal AND confirmed confounder).
  calc_model_summary_zero_strength_count(t.model_summary_id) AS zero_strength_count,-- Studies with StrataWonByLoser=0: no strata go against the pooled winner. These are structurally paradox-free.
  calc_model_summary_partial_count(t.model_summary_id) AS partial_count,        -- Studies with ParadoxStrength > 0 but IsReversal=FALSE: partial paradoxes real but not formally complete.
  calc_model_summary_total_paradox_strength(t.model_summary_id) AS total_paradox_strength,-- Sum of ParadoxStrength across all studies. Used to compute average.
  calc_model_summary_avg_paradox_strength(t.model_summary_id) AS avg_paradox_strength-- Average ParadoxStrength across all studies: TotalParadoxStrength / StudyCount. A scalar summary of how paradox-rich this dataset is.
FROM model_summary t;

-- ----------------------------------------------------------------------------
-- vw_stratum_variables: Table: StratumVariables — one row per study, naming the variable that defines the strata and describing its causal role. A confounder affects both treatment assignment AND outcome; a mediator is downstream of treatment; a contested variable is one where the causal role is disputed. IsConfounder is derived from these two boolean flags.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_stratum_variables CASCADE;
CREATE VIEW vw_stratum_variables WITH (security_invoker = ON) AS
SELECT
  t.stratum_variable_id,                                                        -- Unique slug (e.g. kidney-1986-stone-size).
  calc_stratum_variables_name(t.stratum_variable_id) AS name,                   -- Display label.
  t.study,                                                                      -- FK to the parent Study.
  t.variable_name,                                                              -- The name of the stratifying variable (e.g. stone_size, department, age_group).
  t.causal_role,                                                                -- The variable's causal role: 'confounder' (affects both assignment and outcome), 'mediator' (downstream of treatment), 'contested' (causal role disputed), 'unknown'.
  t.affects_treatment_assignment,                                               -- TRUE if this variable causally influences which treatment a patient receives. Required for confounding.
  t.affects_outcome,                                                            -- TRUE if this variable causally influences the outcome independently of treatment. Required for confounding.
  calc_stratum_variables_is_confounder(t.stratum_variable_id) AS is_confounder, -- TRUE when AffectsTreatmentAssignment AND AffectsOutcome AND CausalRole = 'confounder'. A confounder is the classic driver of Simpson's Paradox.
  t.mechanism_note                                                              -- Plain-language description of how this variable creates the confounding: why it affects both assignment and outcome.
FROM stratum_variables t;

-- ----------------------------------------------------------------------------
-- vw_treatment_rankings: Table: TreatmentRankings — one row per treatment-pair comparison within a study. Derives the pooled winner, the per-stratum winner, and the IsReversal boolean. The paradox emerges here as a derived fact: IsReversal is true when the pooled winner and the per-stratum winner disagree.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_treatment_rankings CASCADE;
CREATE VIEW vw_treatment_rankings WITH (security_invoker = ON) AS
SELECT
  t.treatment_ranking_id,                                                       -- Unique slug (e.g. kidney-1986-A-vs-B).
  calc_treatment_rankings_name(t.treatment_ranking_id) AS name,                 -- Display label.
  t.study,                                                                      -- FK to the parent Study.
  t.treatment_a,                                                                -- Label for the first treatment in the comparison (matches Treatments.TreatmentLabel).
  t.treatment_b,                                                                -- Label for the second treatment in the comparison.
  calc_treatment_rankings_total_cases_a(t.treatment_ranking_id) AS total_cases_a,-- Total cases for TreatmentA across all strata in this study.
  calc_treatment_rankings_total_successes_a(t.treatment_ranking_id) AS total_successes_a,-- Total successes for TreatmentA across all strata.
  calc_treatment_rankings_pooled_rate_a(t.treatment_ranking_id) AS pooled_rate_a,-- Pooled success rate for TreatmentA: TotalSuccessesA / TotalCasesA.
  calc_treatment_rankings_total_cases_b(t.treatment_ranking_id) AS total_cases_b,-- Total cases for TreatmentB across all strata.
  calc_treatment_rankings_total_successes_b(t.treatment_ranking_id) AS total_successes_b,-- Total successes for TreatmentB across all strata.
  calc_treatment_rankings_pooled_rate_b(t.treatment_ranking_id) AS pooled_rate_b,-- Pooled success rate for TreatmentB: TotalSuccessesB / TotalCasesB.
  calc_treatment_rankings_pooled_winner(t.treatment_ranking_id) AS pooled_winner,-- Which treatment wins when strata are ignored: the one with the higher pooled rate.
  calc_treatment_rankings_stratum_count(t.treatment_ranking_id) AS stratum_count,-- Number of strata in this study. Counted from StratumSummaries filtered to TreatmentA rows (one row per stratum).
  calc_treatment_rankings_strata_won_by_a(t.treatment_ranking_id) AS strata_won_by_a,-- Number of strata where A wins: count StratumSummaries rows whose TreatmentLabel=TreatmentA AND StratumWinner=TreatmentA. These are the one-per-stratum sentinel rows.
  calc_treatment_rankings_strata_won_by_b(t.treatment_ranking_id) AS strata_won_by_b,-- Number of strata where B wins: count StratumSummaries rows whose TreatmentLabel=TreatmentA AND StratumWinner=TreatmentB.
  calc_treatment_rankings_per_stratum_winner(t.treatment_ranking_id) AS per_stratum_winner,-- The treatment that wins in every stratum — 'A' if StrataWonByA = StratumCount, 'B' if StrataWonByB = StratumCount, else 'none' (no unanimous per-stratum winner).
  calc_treatment_rankings_is_reversal(t.treatment_ranking_id) AS is_reversal,   -- TRUE when the pooled winner and the per-stratum winner disagree — i.e. Simpson's Paradox is present. FALSE otherwise. This is the paradox as a derived fact, not a modeled entity.
  calc_treatment_rankings_confounders_in_study(t.treatment_ranking_id) AS confounders_in_study,-- Count of StratumVariables in this study whose IsConfounder = TRUE. When > 0, the paradox has a causal explanation.
  calc_treatment_rankings_is_paradox_explained(t.treatment_ranking_id) AS is_paradox_explained,-- TRUE when IsReversal is present AND at least one confirmed confounder exists in the study. The model witnesses its own explanatory completeness — or its limits.
  calc_treatment_rankings_pooled_gap(t.treatment_ranking_id) AS pooled_gap,     -- Absolute difference between the two pooled rates: |PooledRateA - PooledRateB|. The size of the aggregate misleading signal.
  calc_treatment_rankings_strata_won_by_loser(t.treatment_ranking_id) AS strata_won_by_loser,-- Number of strata won by the pooled loser — the counter-signal. For full reversals this equals StratumCount; for partial paradoxes it is between 0 and StratumCount.
  calc_treatment_rankings_paradox_strength(t.treatment_ranking_id) AS paradox_strength,-- Scalar severity of the paradox: PooledGap × (StrataWonByLoser / StratumCount). Zero when no strata go against the pooled winner. Positive for partial paradoxes. Maximum when every stratum contradicts the pooled result.
  calc_treatment_rankings_pooled_rate_from_weights_a(t.treatment_ranking_id) AS pooled_rate_from_weights_a,-- Pooled rate for TreatmentA reconstructed as a weighted average of stratum rates: SUM(WeightedStratumRate) across all stratum rows for TreatmentA. Must match PooledRateA — this witnesses the mechanism equation: the pooled rate IS a weighted average of stratum rates, weighted by StratumFraction.
  calc_treatment_rankings_pooled_rate_from_weights_b(t.treatment_ranking_id) AS pooled_rate_from_weights_b-- Pooled rate for TreatmentB reconstructed as a weighted average. Must match PooledRateB. If it does, the mechanism equation is verified: reversal is purely a consequence of differential weighting.
FROM treatment_rankings t;

